import { ChatFlow } from 'flowise/dist/src';

const detectChainValidationErrors = (chatflow: ChatFlow, executionData: any[]) => {
  return executionData.filter(node => {
    if (node.type === 'LLMChain') {
      try {
        const output = node.data.output;
        JSON.parse(output);
        return false;
      } catch (e) {
        return {
          nodeId: node.id,
          error: 'Invalid JSON output',
          output: node.data.output,
          severity: 'HIGH'
        };
      }
    }
    return false;
  });
};

const detectLowRelevanceDocs = (retrieverNodes: any[]) => {
  return retrieverNodes.map(node => {
    const docs = node.data.sourceDocuments || [];
    const lowRelevance = docs.filter(doc => 
      (doc.metadata?.score || 0) < 0.7
    );

    return {
      nodeId: node.id,
      lowRelevanceCount: lowRelevance.length,
      avgScore: docs.reduce((sum, d) => sum + (d.metadata?.score || 0), 0) / docs.length,
      alert: lowRelevance.length > 2
    };
  }).filter(result => result.alert);
};

const detectSilentToolFailures = (customNodes: any[]) => {
  return customNodes.filter(node => {
    const hasErrorLog = node.data.logs?.some(log => log.includes('ERROR'));
    const outputIsEmpty = !node.data.output || node.data.output === 'null';

    return outputIsEmpty && !hasErrorLog;
  }).map(node => ({
    nodeId: node.id,
    toolName: node.data.toolName,
    input: node.data.input,
    error: 'Silent tool failure detected',
    severity: 'CRITICAL'
  }));
};

