const filterByRelevance = (documents: any[]) => {
  const MIN_SCORE = 0.75;
  return documents.filter(doc => {
    const score = doc.metadata?.score || 0;
    if (score < MIN_SCORE) {
      console.warn(`Filtered low-relevance doc: ${score}`);
      return false;
    }
    return true;
  });
};

