import { Vex } from '@vex_dev/sdk';
import { ChatFlow, FlowRunner } from 'flowise';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY
});

const flowiseCallbackHandler = {
  handleLLMEnd: async (output: any, node: any) => {
    // Auto-detect JSON validation failures
    try {
      JSON.parse(output);
    } catch {
      await vex.capture({
        error: 'LLMChain JSON validation failed',
        nodeId: node.id,
        metadata: { output },
        fix: 'Add JSON validation node'
      });
    }
  },

  handleRetrieverEnd: async (docs: any[], node: any) => {
    const lowRelevance = docs.filter(d => (d.metadata?.score || 0) < 0.7);
    if (lowRelevance.length > 0) {
      await vex.capture({
        error: 'Low relevance documents',
        nodeId: node.id,
        count: lowRelevance.length,
        autoFix: 'Insert relevance filter node'
      });
    }
  },

  handleCustomEnd: async (output: any, node: any) => {
    if (!output && !node.errorLogged) {
      await vex.capture({
        error: 'Silent custom tool failure',
        nodeId: node.id,
        severity: 'CRITICAL',
        autoRemediate: true
      });
    }
  }
};

// Register Vex callback with Flowise
const chatflow = await ChatFlow.load(flowConfig);
chatflow.setCallbackHandler(flowiseCallbackHandler);

// Vex auto-remediation listener
vex.on('error_detected', async (issue) => {
  if (issue.autoFix) {
    await vex.applyFix(issue.nodeId, issue.fix);
  }
});
